mapper.select:
SELECT u.user_no AS userNo, u.user_id AS userId, u.user_name AS userName, u.user_grade AS userGrade, u.insa_code AS teamCode, g.team_name AS teamName, u.user_email AS email FROM pi_user u LEFT JOIN pi_group g ON u.insa_code = g.insa_code WHERE u.acc_yn = 'Y'
AND (u.user_id LIKE CONCAT('%', #{keyword}, '%') OR u.user_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY u.user_name ASC LIMIT #{offset}, #{limit}

SELECT t.TARGET_ID AS targetId, t.NAME AS targetName, COALESCE(a.AGENT_CONNECTED_IP, tg.connected_ip) AS targetIp, t.PLATFORM AS targetOs, a.AGENT_VERSION AS agentVersion, CASE WHEN a.agent_connected = 1 THEN 'CONNECTED' ELSE 'DISCONNECTED' END AS agentStatus, COALESCE(ptg.name, '미그룹') AS groupName FROM pi_targets t LEFT JOIN pi_agents a ON t.NAME = a.AGENT_NAME AND t.AP_NO = a.AP_NO AND a.AGENT_USE = 'Y' LEFT JOIN pi_target_group tg ON tg.TARGET_ID = t.TARGET_ID AND t.AP_NO = tg.AP_NO LEFT JOIN pi_target_group ptg ON tg.up_idx = ptg.idx WHERE t.TARGET_USE = 'Y'
AND (t.NAME LIKE CONCAT('%', #{keyword}, '%') OR a.AGENT_CONNECTED_IP LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY t.NAME ASC LIMIT #{offset}, #{limit}

SELECT t.TARGET_ID AS targetId, t.NAME AS targetName, COALESCE(a.AGENT_CONNECTED_IP, tg.connected_ip) AS targetIp, t.PLATFORM AS targetOs, tg.idx AS groupId, COALESCE(ptg.name, '미그룹') AS groupName FROM pi_targets t LEFT JOIN pi_agents a ON t.NAME = a.AGENT_NAME AND t.AP_NO = a.AP_NO AND a.AGENT_USE = 'Y' LEFT JOIN pi_target_group tg ON tg.TARGET_ID = t.TARGET_ID AND t.AP_NO = tg.AP_NO LEFT JOIN pi_target_group ptg ON tg.up_idx = ptg.idx WHERE t.TARGET_USE = 'Y'
AND t.group_idx IN ( WITH RECURSIVE CTE AS ( SELECT IDX FROM pi_target_group WHERE IDX = #{groupId} UNION ALL SELECT tg2.IDX FROM pi_target_group tg2 INNER JOIN CTE ON tg2.UP_IDX = CTE.IDX ) SELECT IDX FROM CTE )
ORDER BY t.NAME ASC LIMIT #{offset}, #{limit}
